import { useState, useCallback } from 'react';

import { useSegments } from './useSegments.js';

/**
 * Retrieves and formats the display messages for the segments tooltip.
 * @internal
 */
export const useTooltipHandler = (
  readableTrigger: boolean,
): {
  onOpenTooltip: (isOpen: boolean) => void;
  isOpen: boolean;
  textEllipsisRef: (ref: HTMLSpanElement | null) => void;
} => {
  const [ref, setRef] = useState<HTMLSpanElement | null>(null);
  const [isOpen, setIsOpen] = useState(false);

  const { segments } = useSegments();

  const textEllipsisRef = useCallback((ref: HTMLSpanElement | null) => {
    if (ref) {
      setRef(ref);
    }
  }, []);

  const onOpenTooltip = useCallback(
    (open: boolean) => {
      if (!open) {
        setIsOpen(false);
        return;
      }

      // Show the no segments applied message in tooltip.
      const noSelection = !segments || segments.length === 0;
      const contentFits = !(ref && ref.scrollWidth !== ref.clientWidth);
      const moreSegmentsSelected = segments.length > 1;
      // Variables are not shown on the trigger, therefore, we always show the tooltip
      const singleSegmentWithVariables =
        segments.length === 1 &&
        (segments?.[0]?.variables?.[0]?.values.length ?? 0) > 1;

      setIsOpen(
        noSelection ||
          !readableTrigger ||
          moreSegmentsSelected ||
          !contentFits ||
          singleSegmentWithVariables,
      );
    },
    [segments, readableTrigger, ref],
  );

  return {
    onOpenTooltip,
    isOpen,
    textEllipsisRef,
  } as const;
};
